  1	import * as React from 'react';
  2	import { DropdownList, MenuToggle, MenuToggleElement, TooltipPosition } from '@patternfly/react-core';
  3	import { Dropdown } from '@patternfly/react-core';
  4	import { serverConfig } from '../../config';
  5	import { Workload } from '../../types/Workload';
  6	import {
  7	  buildAnnotationPatch,
  8	  WIZARD_DISABLE_AUTO_INJECTION,
  9	  WIZARD_ENABLE_AUTO_INJECTION,
 10	  WIZARD_REMOVE_AUTO_INJECTION,
 11	  WIZARD_EDIT_ANNOTATIONS
 12	} from './WizardActions';
 13	import * as API from '../../services/Api';
 14	import * as AlertUtils from '../../utils/AlertUtils';
 15	import { MessageType } from '../../types/MessageCenter';
 16	import { WizardLabels } from './WizardLabels';
 17	import { renderDisabledDropdownOption } from 'utils/DropdownUtils';
 18	import { WorkloadWizardActionsDropdownGroup } from './WorkloadWizardActionsDropdownGroup';
 19	import { t } from 'utils/I18nUtils';
 20	import { getGVKTypeString, isGVKSupported } from '../../utils/IstioConfigUtils';
 21	import { gvkType } from '../../types/IstioConfigList';
 22	
 23	interface Props {
 24	  namespace: string;
 25	  onChange?: () => void;
 26	  workload: Workload;
 27	}
 28	
 29	export const WorkloadWizardDropdown: React.FC<Props> = (props: Props) => {
 30	  const [isActionsOpen, setIsActionsOpen] = React.useState<boolean>(false);
 31	  const [showWizard, setShowWizard] = React.useState<boolean>(false);
 32	
 33	  const onActionsSelect = (): void => {
 34	    setIsActionsOpen(!isActionsOpen);
 35	  };
 36	
 37	  const onActionsToggle = (isOpen: boolean): void => {
 38	    setIsActionsOpen(isOpen);
 39	  };
 40	
 41	  const onWizardToggle = (isOpen: boolean): void => {
 42	    setShowWizard(isOpen);
 43	  };
 44	
 45	  const onChangeAnnotations = (annotations: { [key: string]: string }): void => {
 46	    const jsonInjectionPatch = buildAnnotationPatch(annotations);
 47	
 48	    API.updateWorkload(
 49	      props.namespace,
 50	      props.workload.name,
 51	      props.workload.gvk,
 52	      jsonInjectionPatch,
 53	      'json',
 54	      props.workload.cluster
 55	    )
 56	      .then(_ => {
 57	        AlertUtils.add(`Workload ${props.workload.name} updated`, 'default', MessageType.SUCCESS);
 58	      })
 59	      .catch(error => {
 60	        AlertUtils.addError(`Could not update workload ${props.workload.name}`, error);
 61	      })
 62	      .finally(() => {
 63	        setShowWizard(false);
 64	
 65	        if (props.onChange) {
 66	          props.onChange();
 67	        }
 68	      });
 69	  };
 70	
 71	  const onAction = (key: string): void => {
 72	    switch (key) {
 73	      case WIZARD_ENABLE_AUTO_INJECTION:
 74	      case WIZARD_DISABLE_AUTO_INJECTION:
 75	      case WIZARD_REMOVE_AUTO_INJECTION: {
 76	        setShowWizard(false);
 77	
 78	        if (props.onChange) {
 79	          props.onChange();
 80	        }
 81	
 82	        break;
 83	      }
 84	      case WIZARD_EDIT_ANNOTATIONS: {
 85	        onWizardToggle(true);
 86	        break;
 87	      }
 88	      default:
 89	        console.log('Unrecognized key');
 90	    }
 91	  };
 92	
 93	  const validActions =
 94	    //  istio actions
 95	    (serverConfig.kialiFeatureFlags.istioInjectionAction && !props.workload.isAmbient) ||
 96	    // annotations
 97	    getGVKTypeString(props.workload.gvk) === getGVKTypeString(gvkType.Deployment);
 98	
 99	  const supportedWorkload = isGVKSupported(props.workload.gvk);
100	
101	  const dropdown = (
102	    <Dropdown
103	      data-test="workload-actions-dropdown"
104	      id="actions"
105	      toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
106	        <MenuToggle
107	          ref={toggleRef}
108	          id="actions-toggle"
109	          onClick={() => onActionsToggle(!isActionsOpen)}
110	          data-test="workload-actions-toggle"
111	          isExpanded={isActionsOpen}
112	          isDisabled={!validActions || !supportedWorkload}
113	        >
114	          {t('Actions')}
115	        </MenuToggle>
116	      )}
117	      isOpen={isActionsOpen}
118	      onOpenChange={(isOpen: boolean) => onActionsToggle(isOpen)}
119	      onSelect={onActionsSelect}
120	      popperProps={{ position: 'right' }}
121	    >
122	      <DropdownList>
123	        <WorkloadWizardActionsDropdownGroup
124	          actionsLabel={false}
125	          annotations={props.workload.annotations}
126	          namespace={props.namespace}
127	          onAction={onAction}
128	          workload={props.workload}
129	        ></WorkloadWizardActionsDropdownGroup>
130	      </DropdownList>
131	    </Dropdown>
132	  );
133	  // TODO WorkloadWizard component contains only 3scale actions but in the future we may need to bring it back
134	  return (
135	    <>
136	      <WizardLabels
137	        showAnotationsWizard={showWizard}
138	        type={'annotations'}
139	        onChange={annotations => onChangeAnnotations(annotations)}
140	        onClose={() => onWizardToggle(false)}
141	        labels={props.workload.annotations}
142	        canEdit={serverConfig.kialiFeatureFlags.istioAnnotationAction && !serverConfig.deployment.viewOnlyMode}
143	      />
144	      {!validActions
145	        ? renderDisabledDropdownOption(
146	            'tooltip_wizard_actions',
147	            TooltipPosition.top,
148	            t('User does not have permission on this Workload'),
149	            dropdown
150	          )
151	        : !supportedWorkload
152	        ? renderDisabledDropdownOption(
153	            'tooltip_wizard_actions',
154	            TooltipPosition.top,
155	            t('This type of workload is read-only'),
156	            dropdown
157	          )
158	        : dropdown}
159	    </>
160	  );
161	};

